let mainWorker = new Worker(mainModule, {
  type: "module",
  name: "main",
});

for await (const event of watcher) {
  if (event.kind === "modify") {
    mainWorker.postMessage({
      type: "reload",
      paths: [mainModule, ...event.paths],
    });

    queueMicrotask(() => {
      mainWorker.terminate();
      mainWorker = new Worker(mainModule + `?t=${new Date().getTime()}`, {
        type: "module",
        name: "main",
      });

      console.log(Deno.resources());
    });
  }
}
```

## Current Situation

Storing the module version as a constant in code makes it harder for tooling and continuous integration to easily obtain the module version or update it,

## Proposed Solution

I propose an optional convention to store the module version in the `import.map.json` or the `deps.ts` files in a effort to keep version stored inside the module and registries like Deno Land easily synchronized.

### import.map.json

> **Note**
> Be aware that this example was written without much thought, maybe a better design is possible

```json
{
  "imports": {
    "@/": "./@1.0.0",
  }
}
```

### Deno.version

```javascript
const version: {
  module: string;
  deno: string;
  v8: string;
  typescript: string;
};
```
```javascript
console.info(`Module version is ${Deno.version.module}`);
// Module version is 1.0.0
```

