Seems like `Deno.inspect(value, { getters: true })` only work on literal Object.

Reproducible code:
```ts
class T {
  get foo() {
    return 42;
  }
}
console.log(Deno.inspect({ get foo() { return 42; } }, { getters: true }));
console.log(Deno.inspect(new T(), { getters: true }));
```
Output:
```txt
{ foo: 42 }
T {}
```
Expected:
```txt
{ foo: 42 }
T { foo: 42 }
```

My quick solution I came up with uses `Object.getOwnPropertyNames` with the instance's prototype to retrieve all the instance's properties.
```ts
function inspect(value: unknown, options?: { depth?: number; indent?: string }) {
  const indent = options?.indent ?? "  ";
  const maxDepth = options?.depth ?? 10;
  return _inspect(value);
  function _inspect(value: unknown, depth = 0) {
    if (value === null) {
      return "null";
    } else if (value === undefined) {
        return "undefined";
    } else if (typeof value === "number") {
      return value.toString();
    } else if (typeof value === "boolean") {
      return value ? "true" : "false";
    } else if (typeof value === "string") {
      return `"${value.replaceAll('"', '\\"')}"`;
    } else if (value instanceof Date) {
      return value.toISOString();
    } else if (Array.isArray(value)) {
      const name = value.constructor.name;
      if (depth > maxDepth) {
        return `${name} [ ${value.length} elements... ]`;
      } else {
        let out = `${name} [\n`;
        for (const val of value.values()) {
          out += `${indent.repeat(depth + 1)}${_inspect(val, depth + 1)},\n`;
        }
        out += `${indent.repeat(depth)}]`;
        return out;
      }
    } else if (typeof value === "object") {
      const name = value.constructor.name;
      const obj = value as Record<string, unknown>;
      const propNames = new Set<string>();
      for (let proto = Object.getPrototypeOf(obj); proto; proto = Object.getPrototypeOf(proto)) {
        for (const key of Object.getOwnPropertyNames(proto)) {
          propNames.add(key);
        }
      }
      const props = Array.from(propNames).filter(n => n !== "constructor" && typeof obj[n] !== "function");
      if (depth > maxDepth) {
        return `${name} { ${props.length} properties... }`;
      } else {
        let out = `${name} {\n`;
        for (const key of props) {
          out += `${indent.repeat(depth + 1)}${key}: ${_inspect(obj[key], depth + 1)},\n`;
        }
        out += `${indent.repeat(depth)}}`;
        return out;
      }
    }
  }
}
class T {
  get foo() {
    return 42;
  }
}
console.log(Deno.inspect({ get foo() { return 42; } }, { getters: true }));
console.log(Deno.inspect(new T(), { getters: true }));
console.log(inspect(new T()));
```

Output:
```txt
{ foo: 42 }
T {}
T {
  foo: 42
}
```

