The following code incorrectly checks that only the supported hash<>namedCurve algorithms are used.

https://github.com/denoland/deno/blob/86785f21194460d713276dca212302fa1bb1c943/ext/crypto/lib.rs#L260-L279

Given the only combinations that are meant to be supported (based on the code comment) are P-256 w/ SHA-256 and P-384 w/ SHA-384 the following code demonstrates the issues that arise.

```ts
import { assert } from "https://deno.land/std@0.178.0/testing/asserts.ts";

const data = new TextEncoder().encode('Hello')

for (const keyAlgorithm of [{ name: 'ECDSA', namedCurve: 'P-256' }, { name: 'ECDSA', namedCurve: 'P-384' }]) {
  const kp = await crypto.subtle.generateKey(keyAlgorithm, false, ['sign', 'verify'])
  let signature;
  // P-256 w/ SHA-256; P-384 w/ SHA-384
  {
    const algorithm = { name: keyAlgorithm.name, hash: { name: keyAlgorithm.namedCurve === 'P-256' ? 'SHA-256' : 'SHA-384' } }
    signature = await crypto.subtle.sign(algorithm, kp.privateKey, data)

    const verified = await crypto.subtle.verify(algorithm, kp.publicKey, signature, data)
    assert(verified)
  }

  // SHA-1, SHA-512, and not matching SHA w/ P-256 and 384 should error
  {
    for (const hash of ["SHA-1", "SHA-512", keyAlgorithm.namedCurve === 'P-256' ? 'SHA-384' : 'SHA-256']) {
      const algorithm = { name: keyAlgorithm.name, hash: { name: hash } }
      await crypto.subtle.sign(algorithm, kp.privateKey, data).then(() => {
        console.log(`${keyAlgorithm.namedCurve} w/ ${hash} SIGN did not reject, it should`)
      }, (err) => {
        assert(err.message === 'Not implemented' || err.message === 'Unsupported algorithm')
      })
      await crypto.subtle.verify(algorithm, kp.publicKey, signature, data).then((verified) => {
        console.log(`${keyAlgorithm.namedCurve} w/ ${hash} VERIFY did not reject, it should, or at the very least not verify`)
        console.log(`${keyAlgorithm.namedCurve} w/ ${hash} VERIFY verified:`, verified, verified === true ? '❌' : '✅')
      }, (err) => {
        assert(err.message === 'Not implemented' || err.message === 'Unsupported algorithm')
      })
    }
  }
}

```

