Some frontend (Browser) code of mine doing localStorage caching of response contents but then has to check the last-modified header with a (supposedly faster, or at least equally fast with smaller payload) HEAD request, but as you can see, the difference is massive, yes, the body is not there, therefore the payload is much smaller, which is good, but instead of taking also 12ms or less to respond, the server takes ballpark 200ms to do so (it is based on https://github.com/hviana/faster/blob/master/server.ts which internally uses `Deno.serveHttp(conn);` but that's why I think there might be an underlying issue with Deno and HEAD requests)

I use my own serveStatic middleware, which does the same `Deno.stat()` call for both HEAD and GET requests, so I don't see why a HEAD request would be so dramatically slower than a GET request which then even has to go and read the file contents, any ideas?

```js
// Static file serving middleware
const serveStatic = (root, options = {}) => {
	return async (ctx, next) => {
		// console.log(ctx);
		// Check if URL starts with an excluded route, return early if so
		if ( options.exclude && options.exclude.some((route) => ctx.url.pathname.startsWith(route)) ) {
			await next();
			return;
		}

		// console.log(`Serving ${ctx.req.method} request to static file`, ctx.url.pathname);
		try {	
			// Assemble the static file path
			const path = root + ctx.url.pathname;
			// Get fileinfo, will fail if path does not exist and terminate early
			const stats = await Deno.stat(path);
			// Set proper response headers
			ctx.res.headers = {
				'accept-ranges': 'bytes',
				'connection': 'keep-alive',
				'content-length': stats.size,
				// see https://stackoverflow.com/a/12900504/4428236 for an explanation, gets the extension, fast
				'content-type': mime[path.slice((path.lastIndexOf('.') - 1 >>> 0) + 2)] || 'application/octet-stream',
				'keep-alive': 'max=100, timeout=12',
				'last-modified': stats.mtime.toUTCString(),
			};
			// If HEAD request, return early, HEAD responses do not have a body
			if ( ctx.req.method === 'HEAD' ) { return; }
			// Otherwise create a file handle
			const file = await Deno.open(path, { read: true });
			// Handle range requests
			const range = ctx.req.headers.get('range');
			if ( range && range.startsWith('bytes') ) {
				const [start, end] = range.replace('bytes=', '').split('-').map(Number);
				const chunkSize = end - start + 1;
				await file.seek(start, Deno.SeekMode.Start);
				ctx.res.headers.set('content-range', `bytes ${start}-${end}/${stats.size}`);
				ctx.res.body = readableStreamFromReader(file).slice(chunkSize);
				ctx.res.status = 206;
			} else {
				ctx.res.body = readableStreamFromReader(file);
			}
		} catch (e) {
			ctx.res.status = 404;
		}
		await next();
	};
};
```

